  "title": "सही कोटेशन",
  "group": "कोटेशन 1",
  "options": [
    {
      "text": "दोनों एक समान काम करते हैं"
    },
    {
      "text": "डबल कोट्स अनिवार्य हैं"
    },
    {
      "text": "सिंगल कोट्स अनिवार्य हैं"
    },
    {
      "text": "सिंटैक्स त्रुटि: अमान्य यूज़र लिटरल"
    },
    {
      "text": "सभी नाम लोअरकेस में होने चाहिए"
    }
  ],
  "questionProse": [
    "केस-सेंसिटिव कॉलम नामों के लिए सही कोटिंग कौन सी है?"
  ],
  "explanationProse": [
    "PostgreSQL में कोट्स का उद्देश्य अलग होता है, इसलिए इन्हें सही जगह लगाना ज़रूरी है:\n    - डबल कोट्स (`\"`) का उपयोग आइडेंटिफायर्स (टेबल नाम, कॉलम नाम) के लिए होता है ताकि डेटाबेस उन्हें रिज़र्व्ड कीवर्ड या स्पेशल कैरेक्टर न समझे\n    - सिंगल कोट्स (`'`) का उपयोग केवल स्ट्रिंग लिटरल्स (डेटा वैल्यू) के लिए होता है\n\n    बेस्ट प्रैक्टिसेज़:\n    - नामों में मिक्स्ड केस या स्पेस से बचें ताकि कोटिंग की ज़रूरत ही न पड़े\n    - आइडेंटिफायर्स के लिए हमेशा `snake_case` अपनाएं\n    - कोटेड आइडेंटिफायर्स का उपयोग केवल तभी करें जब यह बिल्कुल अपरिहार्य हो"
  ]
}
